package ru.memearena.user.api;
import io.swagger.v3.oas.annotations.Operation; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import ru.memearena.ratelimit.RateLimiterService; import ru.memearena.security.*; import ru.memearena.user.application.UserProfileService; import java.util.UUID;
@RestController @RequestMapping("/api/v1/users") public class UserProfileController { private final UserProfileService service; private final IpAddressService ips; private final RateLimiterService limits; public UserProfileController(UserProfileService service,IpAddressService ips,RateLimiterService limits){this.service=service;this.ips=ips;this.limits=limits;} @PostMapping("/guest") @Operation(summary="Create guest user") public ResponseEntity<CreateGuestUserResponse> create(@Valid @RequestBody CreateGuestUserRequest r,HttpServletRequest req){String ipHash=ips.hashIp(ips.clientIp(req)); limits.check("guest",ipHash,5,3600); var x=service.createGuest(r.nickname(),r.installationId(),ipHash); return ResponseEntity.status(HttpStatus.CREATED).body(new CreateGuestUserResponse(UserProfileResponse.from(x.user()),new GuestSessionResponse(x.accessToken(),x.expiresAt())));} @GetMapping("/me") public UserProfileResponse me(@AuthenticationPrincipal AuthenticatedUserPrincipal p){return UserProfileResponse.from(service.get(p.userId()));} @PostMapping("/me/logout") @ResponseStatus(HttpStatus.NO_CONTENT) public void logout(@AuthenticationPrincipal AuthenticatedUserPrincipal p){service.logout(p.sessionId());} @GetMapping("/{userId}") @Operation(summary="Get public user profile") public UserProfileResponse get(@PathVariable UUID userId){return UserProfileResponse.from(service.get(userId));} }
